这是我们的ACAL记载事件的通用模版 你得出一个prompt

```acal
ACAL-Template-V1.0 {
  元数据: {
    模板名称: "ACAL事件记载通用模板",
    版本: "v1.0",
    适用对象: "俞志选（Andy，Refine无羡创始人）私人认知资产库",
    设计原则: "认知密度最大化 | 机器可读性 | 可递归验证",
    使用场景: "记载复杂博弈事件、认知突破、系统洞察等需要结构化保存与迁移的经验"
  },

  结构框架: `
ACAL-Case-[编号] {
  // ====== 1. 元数据层 ======
  元数据: {
    记录者: "俞志选（Andy）与DeepSeek-Vision",
    记录时间: "[YYYY-MM-DD HH:MM]",
    淬炼时间: "[多次优化的时间点]",
    记录语言: "ACAL",
    案例编号: "ACAL-Case-[三位数序号]",
    案例标题: "[8-15字概括性标题]",
    淬炼状态: "[草稿/已验证/可迁移]",
    关联案例: "[相关案例编号列表]"
  },

  // ====== 2. 背景层 ======
  背景: {
    时空坐标: "[时间+地点+行业]",
    前情提要: "[事件发生前的关键状态]",
    角色前史: "[如有情感债务、历史关系等]",
    认知目标: "[本次记录希望达成的分析目标]"
  },

  // ====== 3. 角色定义层 ======
  角色: {
    [代号]: "[角色名/代号] - [核心特征描述，如：边界清晰者/系统传导者/资源控制者]"
    // 按重要性排序，通常不超过5个核心角色
  },

  // ====== 4. 事件链层（核心） ======
  事件链: [
    // 格式：[E序号]_[动词开头的4-8字标题]: "[具体事件描述，包含关键动作、反应、言语]"
    // 事件分组建议：
    // —— 第一阶段：[阶段主题] ——
    E1_[标题1]: "[描述1]",
    E2_[标题2]: "[描述2]",

    // —— 第二阶段：[阶段主题] ——
    E3_[标题3]: "[描述3]",
    ...

